var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"어… 저, 저기 좀 보세요.","JPN":"あ……あ、あれを見て。","ENG":"Um... Look over there.","TWN":"呃……快、快看那邊。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHILD_NPC_ANNIE_NONAME","text":{"KOREA":"침식체들이 순식간에…….","JPN":"侵食体があっという間に……","ENG":"The C.O.s just vanished in an instant...","TWN":"侵蝕體們一下子……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"흔적도 없이 증발했어?","JPN":"跡形もなく消えた？","ENG":"They're gone without a trace?","TWN":"連痕跡都蒸發了？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"아무래도 우리 지원 요청을 들은 자들이 엄청난 놈들인가 보군.","JPN":"どうやら俺たちの支援要請に応えてくれたのは、とんでもないやつらだったようだな。","ENG":"Whoever heard our call for help must be top tier.","TWN":"看來支援我們的傢伙們是超級狠角色啊。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"다들, 서두르자고.","JPN":"皆、急ぐぞ。","ENG":"Let's move.","TWN":"大家動作快。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PMC_OMEN_NPC_NULL","text":{"KOREA":"지금은 조용하더라도, 언제 다시 놈들이 쳐들어올지 모르니까.","JPN":"今は落ち着いていても、またいつやつらが襲ってくるか分からない。","ENG":"It's quiet now, but they could come back any time.","TWN":"現在雖然很平靜靜，但不知道什麼時候又會再進攻。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"저… 감사합니다.","JPN":"あの……ありがとうございます。","ENG":"Th-thank you.","TWN":"那個……謝謝各位。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"소속과 성함을 알려주시면 관리국에 보고해 꼭 보답하겠습니다.","JPN":"所属とお名前をお聞きしてもよろしいでしょうか。管理局に報告し、必ず恩返しします。","ENG":"Tell me your affiliation and name. I'll report it to the Administration and make sure you're rewarded.","TWN":"如果能告訴我所屬和姓名，我會向管理局報告，報答各位的恩情。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILD_NPC_ANNIE_NONAME","face":"UNIT_IDLE"},"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":{"char_id":"PMC_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"이 와중에도 공치사를 논하려는 거야? 직업 정신이 투철하네.","JPN":"こんな状況でそれを聞くの？　真面目ね。","ENG":"Even now, you’re trying to take credit? That's some professional dedication","TWN":"這種情況還在討論功勞？真是可怕的職業病。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"흠~ 보수 같은 건 필요 없는데 말이지.","JPN":"う～ん、別に報酬はいらないのよね。","ENG":"Hm... I don't need payment, though.","TWN":"哼～我是不需要什麼報酬啦。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"용감한 후배님이 목숨까지 걸고 나섰는데 어떻게 보수를 바라고 움직이겠어?","JPN":"勇敢な後輩くんが命までかけて戦おうとしているのに、報酬目当てで動いたりしないわ。","ENG":"How could I ask for money when a brave junior like yourself risked his life?","TWN":"後輩這麼勇敢、連命都賭上了，我怎麼能為了報酬才行動呢？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"후…배님이요?","JPN":"後輩……ですか？","ENG":"J-junior?","TWN":"後、後輩……？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"난 코핀 컴퍼니 소속, 알렉스라고해.","JPN":"私はコフィンカンパニー所属、アレックスよ。","ENG":"I'm Alex with Coffin Company.","TWN":"我隸屬科芬公司，名叫雅蕾克絲。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그리고 도시에서 침식체를 정리하고 있는 애들은 예고르, 빅터, 예프넨 그리고…….","JPN":"都市で侵食体を片付けている子たちはイェゴール、ヴィクター、イェフネン、そして……","ENG":"And the ones sweeping the city are Yegor, Viktor, Yevnen, and...","TWN":"還有在城裡清理侵蝕體的那些人分別是伊高爾、維克多、耶芙涅，還有……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"이렇게 하나하나 얘기하다 보면 끝이 없으려나?","JPN":"いちいち名前をあげてたらきりがないわね。","ENG":"If I list them one by one, we'll be here all day.","TWN":"這樣一個個介紹下去大概沒完沒了吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"당신이 이 도시의 총지휘관이야?","JPN":"あなたがこの都市の総指揮官？","ENG":"Are you the acting commander here?","TWN":"你是這座城市的總指揮官嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"지금은… 그렇습니다.","JPN":"今は……そうです。","ENG":"For now... yes.","TWN":"現在……是這樣沒錯。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"저 4종 침식체 녀석이 부상하는 바람에 제 윗사람들은 전부 죽었거든요.","JPN":"あの第4種侵食体が浮上したせいで、私の上司は全員死亡しましたので。","ENG":"That Category 4 C.O. emerged and killed all my superiors.","TWN":"4級侵蝕體浮上來後，我的上司全死了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"……정말 유감이네.","JPN":"……残念だったわね。","ENG":"...That's unfortunate.","TWN":"……真令人遺憾。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"최대한 빨리 온다고 온 건데 이렇게 됐을 줄은…….","JPN":"急いだつもりだったけど、こんなことになっていたなんて……","ENG":"We came as fast as we could, but I didn't expect this...","TWN":"我們已經盡快趕來了，沒想到會變成這樣……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"아닙니다.","JPN":"いいえ。","ENG":"No.","TWN":"不，沒那回事。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"여러분 덕분에 아직 대피하지 못한 사람들이 살아남을 수 있었습니다.","JPN":"皆さんのおかげで、避難できずにいた人々の命が助かりました。","ENG":"Thanks to you, people who hadn't evacuated yet survived.","TWN":"多虧各位，還沒撤離的人才能活下來。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"감사 인사는 저희가… 응?","JPN":"逆にお礼を……うん？","ENG":"We should be thanking– Huh?","TWN":"感謝的話應該由我們……嗯？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"하, 하늘에 비행형 침식체 다수 확인!","JPN":"そ、空に飛行型侵食体を多數確認！","ENG":"M-multiple flying C.O.s in the sky!","TWN":"確、確認天空有大量飛行型侵蝕體！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"저 녀석들도 포격으로 격추할 수 있을까요?","JPN":"あいつらも砲撃で撃墜できるでしょうか？","ENG":"Can you shoot those down with artillery too?","TWN":"能用炮擊擊落那些傢伙嗎？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"음~ 저만한 숫자를 전부 격추하기엔 무리겠는걸.","JPN":"うーん、あの数を全部落とすのは無理ね。","ENG":"Hm... Not all of them, not in those numbers.","TWN":"嗯～數量那麼多，要全部擊落有點勉強。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"절반 정도는 어떻게 처리할 수 있으려나?","JPN":"半分ぐらいなら、なんとかできるかも？","ENG":"Maybe half, at best.","TWN":"大概能處理一半吧？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"그, 그런…….","JPN":"そ、そんな……","ENG":"Th-that's...","TWN":"這、這怎麼……"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"시간이 없습니다!","JPN":"時間がありません！","ENG":"We don't have time!","TWN":"沒時間了！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"빨리 도시에 연락해서 사람들을 다시 건물 안으로 피신시켜야……!","JPN":"早く都市に連絡し、人々を建物の中に移動させないと……！","ENG":"We need to alert the city and get everyone back inside buildings–!","TWN":"得趕快聯絡城市，讓大家再次撤回建築物內避難……！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"너무 걱정하지 마, 후배님.","JPN":"心配しないでちょうだい。","ENG":"Don't worry too much, junior.","TWN":"別太擔心，後輩。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"우리 애들이 저 녀석들을 전부 격추하지 못하더라도.","JPN":"うちの子どもたちが、あいつらを全部撃ち落とすことは難しいけど……","ENG":"Even if my guys can't shoot them all down,","TWN":"即使我們的人無法全部擊落那些傢伙，"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"하늘에선 아무도 막지 못하는 귀여운 중사님이 계시거든.","JPN":"空には、誰にも止められない可愛い軍曹がいるの。","ENG":"there's a certain cute sergeant nobody can stop in the air.","TWN":"空中可是有一位誰也擋不住的可愛中士呢。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"여긴 그리핀 1. 비행형 침식체 다수, 침묵 확인했습니다.","JPN":"こちらはグリフィン1。飛行型侵食体多數、沈黙を確認しました。","ENG":"This is Griffin 1. Multiple flyers confirmed, now silent.","TWN":"這裡是獅鷲1號。已確認多數飛行型侵蝕體沉默。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_COMMANDER","text":{"KOREA":"치, 침식체들이 전부 격추됐어?","JPN":"し、侵食体が全部撃墜された？","ENG":"Th-the C.O.s were all shot down?","TWN":"擊落所有侵、侵蝕體？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"좋은 타이밍이었어, 중사님.","JPN":"いいタイミングだったわ、軍曹。","ENG":"Perfect timing, Sergeant.","TWN":"時機剛剛好呢，中士。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"우리 전대 관측관으로 들어올 생각은 없어?","JPN":"うちの戦隊の観測官になる気はない？","ENG":"Interested in joining us as our division's observer?","TWN":"要不要考慮加入我們戰隊當觀測官？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_IDLE"},"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"아, 하하하… 말씀은 감사합니다.","JPN":"あ、ははは……嬉しいお言葉ありがとうございます。","ENG":"Ah, hahaha... I appreciate the offer.","TWN":"啊，哈哈哈……謝謝您的好意。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_COMMANDER","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_PRIDE"},"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님. 방위선을 구축할 준비는 완료되었습니다.","JPN":"副戦隊長。防衛線構築の準備が整いました。","ENG":"Deputy Commander, we're ready to establish the defense line.","TWN":"副隊長，已準備好構築防線了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"이터니움 광맥의 경우, 사막에 자리 잡고 있어 차원 폭풍에 방위선이 노출될 위험이 있습니다.","JPN":"エタニウム鉱脈の場合、砂漠に位置するため次元の暴風に防衛線がさらされる危険があります。","ENG":"The Eternium vein sits in the desert, so the line would be exposed to dimensional storms.","TWN":"永恆之金礦脈位於沙漠中，防線有暴露在次元風暴的危險性。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"일단 그쪽도 확보하시겠습니까?","JPN":"一旦そちらも確保しましょうか？","ENG":"Should we secure that area as well?","TWN":"要一起確保那邊的安全嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"이번 작전의 핵심은 이터니움을 최대한 많이 확보하는 거야.","JPN":"今回の作戦の要は、エタニウムをなるべく多く確保することよ。","ENG":"The core of this op is securing as much Eternium as possible.","TWN":"本次作戰的核心，就是盡可能多取得永恆之金。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"마왕의 발목을 붙잡기 위해선 우리 쪽도 꽤 많은 준비가 필요하다고 들었거든.","JPN":"魔王を足止めするためには、こっちもしっかり備えておく必要があると聞いたわ。","ENG":"We need a lot of prep on our side to trip up the Demon Lord. That's what I heard.","TWN":"聽說為了牽制魔王，我們也得做不少準備。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"날벌레들이 좀 많이 꼬이기야 하겠지만…","JPN":"多少、コバエが寄って来るでしょうけど……","ENG":"We'll draw a lot of gnats, sure...","TWN":"雖然會招惹一堆麻煩事……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"우리가 겪었던 클리포트 게임만 하겠어?","JPN":"私たちが経験したクリフォトゲームに比べれば、まだマシなんじゃない？","ENG":"But compared to the Qliphoth Game we went through, this is nothing.","TWN":"會有比逆卡巴拉遊戲更麻煩的事嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"게다가 마왕 쪽에서 습격했다고 들었어요.","JPN":"それに、先に打って出たのは魔王側だと聞きました。","ENG":"I also heard the Demon Lord's side launched a raid.","TWN":"而且聽說魔王那邊也發動襲擊。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그쪽도 습격을 준비한 만큼, 어딘가 감수해야 할 취약점이 있겠죠.","JPN":"何かしらのリスクを背負う羽目になっても、自分たちから襲撃を仕掛けた方がよりメリットがある……という算段でしょうか。","ENG":"If they prepared an assault, there must be weak points they are accepting.","TWN":"既然他們也在準備襲擊，那必定有需要承受的弱點。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"후후, 역시 중사님. 짬이 어디 안 간다니까?","JPN":"ふふ、さすが軍曹。勘は鈍っていないようね。","ENG":"Heh heh, that is our sergeant. Experience shows.","TWN":"呵呵，不愧是中士，還是寶刀未老呢？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"중사님 말대로 마왕 휘하의 세력들은 함부로 현실 세계로 넘어올 수 없어.","JPN":"軍曹の言った通り、魔王配下の勢力は迂闊に現実世界へと足を踏み入れることはできない。","ENG":"Like you said, the Demon Lord's forces can't cross into the Normalside at will.","TWN":"按照中士的說法，魔王麾下的勢力無法隨便進入現實世界。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"클리포트 게임의 규칙 때문에 현실 세계에 영향력을 끼치려고 하면 힘에 제약이 걸리거든.","JPN":"クリフォトゲームのルールのせいで、現実世界に影響を与えようとすると力が制限されるのよ。","ENG":"The rules of the Qliphoth Game limit their power when they try to influence the Normalside.","TWN":"因為逆卡巴拉遊戲的規則，只要試著影響現實世界，力量就會受限。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"뭐, 현실에 개입하려는 시도 자체가 그런 규칙 같은 걸 신경 쓰지 않는다는 소리지만.","JPN":"まあ、現実介入を試みる時点で、そういうルールは気にしていないってことでしょうけど。","ENG":"Which also means they don't care much about those rules if they're trying anyway.","TWN":"不過，會嘗試介入現實這件事，就代表他們根本不把這些規則放在眼裡。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그럼 뭔가 이상하네요.","JPN":"それはおかしいですね。","ENG":"Then it's odd.","TWN":"那就奇怪了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"제약을 각오하면서까지 현실에 개입하려고 하는 이유가 뭘까요?","JPN":"力が制限されることを覚悟してまで、現実に介入しようとする理由はなんでしょうか？","ENG":"Why force an intervention in reality despite the limits?","TWN":"既然明知道受限，為什麼還要介入現實世界呢？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"단순히 힘을 기르려는 목적이라면 그만한 게 없다고 들었거든.","JPN":"単純に力をつけることが目的なら、それが一番手っ取り早いからね。","ENG":"If the goal is to grow stronger, there's nothing better.","TWN":"我聽說如果只是為了增強力量，這是最好的途徑。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"마왕은 다른 세계를 자신의 클리파 차원에 귀속시키는 것으로 힘을 기를 수 있다고 하니까.","JPN":"魔王は他の世界を自分のクリファ次元に帰属させれば、力を更につけられるらしいわ。","ENG":"The Demon Lord can gain power by subsuming other worlds into its Qlipha Dimension.","TWN":"聽說魔王把其他世界併入自己的逆卡巴拉次元就能變強。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그것 참 끔찍한 일이네요.","JPN":"そうなったらと思うとぞっとしますね。","ENG":"That's horrific.","TWN":"真可怕。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그래서 우리가 이렇게 필사적으로 막고 있는 거야.","JPN":"だからこうやって、私たちが必死に止めているのよ。","ENG":"That's why we're fighting this hard to stop it.","TWN":"所以我們才會這麼拼命阻止。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"출발하자, 중사님.","JPN":"行きましょう、軍曹。","ENG":"Let's move, Sergeant.","TWN":"出發吧，中士。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"마왕이 뭔가 다른 수를 쓰기 전에 우리 쪽에서도 준비를 마쳐야 해.","JPN":"魔王が他の手を打つ前に、こっちの準備を済ませておかないと。","ENG":"We need to be ready before the Demon Lord tries anything else.","TWN":"在魔王使出別的手段前，我們也得盡快完成準備。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"이걸로 운송할 수 있는 이터니움은 전부 챙긴 것 같습니다.","JPN":"これで輸送できるエタニウムはすべて確保できたと思います。","ENG":"That's all the Eternium we can transport with this.","TWN":"能運出的永恆之金似乎全都帶上了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그런데… 그 선로전환기란 게 뭔지 물어봐도 되겠습니까?","JPN":"ところで……その線路転換器というものについてお聞きしてもよろしいでしょうか。","ENG":"By the way, what exactly is this Track Switcher?","TWN":"不過……我能問那個叫線路轉換器的東西到底是什麼嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"나도 그이한테 듣기만 해서 자세하게는 몰라.","JPN":"私も彼に聞いただけで、詳細はわからないわ。","ENG":"I only heard about it from the Supreme Administrator, so I don't know the details.","TWN":"我也只是聽說的，不太清楚細節。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"차원 도약하는 개체들의 목표 좌표를 비틀어서 완전히 다른 곳으로 나오게 하는 거랬나?","JPN":"次元跳躍する個体の目標座標を捻じ曲げ、完全に別の場所に出るようにする装置、と言ったっけ。","ENG":"It twists the target coordinates of dimension-jumping entities so they emerge somewhere totally different, right?","TWN":"好像是扭曲那些進行次元跳躍的個體的目標座標，讓它們從別的地方現身的裝置？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"함선을 대상으로 한 시험에는 성공했다고 들었는데, 실전 배치는 이번이 처음이라 하더라고.","JPN":"艦船対象の実験には成功したらしいけど、実戦で使うのは今回が初めてらしいの。","ENG":"Tests on ships succeeded, but this is the first real deployment.","TWN":"聽說對艦船進行試驗時成功了，但實際應用到戰鬥還是第一次。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"특히나 마왕을 상대하기 위해선 막대한 양의 연료, 이터니움이 필요하고.","JPN":"特に相手が魔王ともなると、莫大な量の燃料……エタニウムが必要みたいだし。","ENG":"And to take on the Demon Lord, it needs a huge amount of fuel. In other words, a lot of Eternium.","TWN":"尤其對付魔王，需要大量的永恆之金燃料。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래서 이 도시의 이터니움 광맥이 필요한 거였군요.","JPN":"それでこの都市のエタニウム鉱脈が必要だったんですね。","ENG":"So that's why this city's Eternium vein matters.","TWN":"所以才需要這座城市的永恆之金礦脈啊。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"무리해서 이곳까지 방위선을 구축하려는 이유가 있었네요.","JPN":"……身を挺してまで、ここにも防衛線を築こうとした理由がわかりました。","ENG":"That's also why we are pushing to extend the line here.","TWN":"難怪要拼命在這邊構築防線。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"문제가 있다면… 언제까지 방위선을 유지해야 하냐는 거지.","JPN":"問題は……防衛線をいつまで保てばいいか、ね。","ENG":"The question is how long we can hold the line.","TWN":"問題是……得維持防線到什麼時候。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"저 대균열이 얼마나 넓어질지도 모르고, 저기서 튀어나오는 침식체들이 얼마나 계속 몰려들지도 모르니…….","JPN":"あの大亀裂がどこまで拡張するかもわからないし、そこからどれくらいの侵食体が湧き出てくるのかもわからない……","ENG":"We don't know how wide that Grand Dimension Crevice will get, or how long C.O.s will keep pouring out.","TWN":"不知道大峽谷會擴大到多少，也不知道會從裡面湧出多少侵蝕體……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"우리는 한동안 ARC-EX를 지키고 있어야 할지도 모르겠네.","JPN":"私たち、しばらくはARC-EXを見守らないといけないかも。","ENG":"We might have to defend ARC-EX for a while.","TWN":"說不定我們得守著ARC-EX一段時間。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"CSE 레벨이 4가 되지 않은 시점에서 이터가 부상했습니다.","JPN":"CSEレベルが4にも達してない状態で、イーターが浮上しました。","ENG":"An Eater emerged before CSE level hit 4.","TWN":"在CSE等級還沒到4的時候，吞噬型就浮上來了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L15_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"언제 다시 이터니움을 촉매 삼아 나타날지 모르니 면밀히 감시해야죠.","JPN":"またエタニウムを触媒にして現れるかもしれません。細心の注意を払わねば。","ENG":"It could reappear using Eternium as a catalyst, so we should keep close watch.","TWN":"不知道何時又會以永恆之金催化劑現身，得密切監視才行。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"음? 중사님은 왜 화난 레서판다 같은 얼굴을 하고 있어?","JPN":"うん？　どうしたの、軍曹？　怒ったレッサーパンダみたいな顔して。","ENG":"Hmm? Why the angry red panda face, Sergeant?","TWN":"嗯？中士為什麼一臉像個生氣的小熊貓？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭔가 이상하다 싶어서요.","JPN":"何か変だと思って。","ENG":"Something feels off.","TWN":"總覺得哪裡不太對勁。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"ARC-EX와 ARC-EA2는 둘 다 직할 도시에서 조금 떨어진 구역이잖아요?","JPN":"ARC-EXとARC-EA2はどれも直轄都市から少し離れた区域ですよね。","ENG":"ARC-EX and ARC-EA2 are both a bit removed from the Direct Control City, right?","TWN":"ARC-EX跟ARC-EA2都是在稍微脫離直轄城市的地區吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"게다가 두 곳 모두 이터니움 보관소가 있었다는 우연한 공통점이 있고요.","JPN":"それに両都市には偶然にも、エタニウム保管所があるという共通点がありました。","ENG":"And both just happen to have Eternium depots.","TWN":"而且兩個地方都有永恆之金保管所這個共通點。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"제가 듣기론 그쪽엔 알파트릭스가 있었다고 들었는데…….","JPN":"聞いた話だと、向こうにはアルファトリックスがいたようですけど……","ENG":"I heard Alphatrix was over there...","TWN":"我聽說那邊有阿爾法崔克斯……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그럼 어째서 대균열에 제일 가까운 직할 도시는 비교적 피해가 미미했던 걸까요?","JPN":"なら、なぜ大亀裂に一番近い直轄都市は、比較的被害が少なかったのでしょうか。","ENG":"So why has the Direct Control City closest to the Grand Dimension Crevice suffered relatively minor damage?","TWN":"那為什麼距離大峽谷最近的直轄城市反而受損較小呢？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"만약 저라면 변수가 될 수 있는 외부 요인이 없는 지금 직할 도시를 습격했을걸요?","JPN":"私だったら、変数となり得る外部要因のなくなった今、直轄都市を攻めます。","ENG":"If it were me, I would've attacked the Direct Control City now, when there are fewer external factors.","TWN":"如果是我，在外部變因最少的情況下，一定會襲擊直轄城市啊。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"실제로 알렉스 씨와 제가 여기 발이 묶였잖아요.","JPN":"実際、アレックスさんと私は今ここに足止めされてますし。","ENG":"In fact, you and I are stuck here.","TWN":"實際上，雅蕾克絲和我都被困在這裡了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"일리 있는 말이야.","JPN":"一理ある話ね。","ENG":"You have a point.","TWN":"有道理。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"내가 저쪽 지휘관이었어도 상대하기 까다로운 적들은 무슨 수를 써서라도 발을 묶었을 거야.","JPN":"私が敵の指揮官だったら、相手しづらい敵はどんな手を使ってでも足止めするわ。","ENG":"If I were commanding them, I would do anything to tie down the toughest enemies.","TWN":"如果我是那邊的指揮官，也會不惜一切代價牽制難纏的敵人。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"로터스로 가야 해요.","JPN":"ロータスに行かないと。","ENG":"We need to get to Lotus.","TWN":"我們必須去洛德斯。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"놈들이 원하는 게 바로 우리가 이 도시에 발이 묶이는 상황이라고요.","JPN":"やつらの狙いは、私たちがこの都市から動けない状況です。","ENG":"This is exactly what they want, for us to be stuck in this city.","TWN":"他們要的就是把我們被困在這座城市。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"여기는 로터스 제5 격납고!","JPN":"こちらはロータス第5格納庫！","ENG":"This is Lotus Hangar 5!","TWN":"這裡是洛德斯第5機庫！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"현재 침식체의 습격으로 고립된 상황이다!","JPN":"現在、侵食体の襲撃により孤立している！","ENG":"We are cut off by a C.O. assault!","TWN":"目前正因侵蝕體襲擊陷入孤立狀態！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_03"},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"이 무전을 듣고 있는 모두에게 지원을 요청한다!","JPN":"この無線を聞いている全員に支援を要請する！","ENG":"Requesting support from anyone hearing this transmission!","TWN":"向所有現在收聽的人請求支援！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"다시 한번 알린다!","JPN":"繰り返す！","ENG":"I repeat!","TWN":"再重複一次！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"여기는 로터스 제5 격납고!","JPN":"こちらはロータス第5格納庫！","ENG":"This is Lotus Hangar 5!","TWN":"這裡是洛德斯第5機庫！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"현재 침식체의 습격으로…….","JPN":"現在、侵食体の襲撃により……","ENG":"We are cut off by a C.O...","TWN":"目前正因侵蝕體襲擊……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};